#!/usr/bin/env node

/**
 * Generate Theme Template
 *
 * Reads the level-specific themeable token templates from tokens/dist/
 * (auto-generated by StyleDictionary from the token sources) and writes them as
 * starting-point templates for theme authors.
 *
 * Outputs:
 *   - theme-template.css          ← from themeable-tokens-starter.css  (backwards-compat alias)
 *   - theme-template-starter.css  ← from themeable-tokens-starter.css
 *   - theme-template-extended.css ← from themeable-tokens-extended.css
 *   - theme-template-advanced.css ← from themeable-tokens-advanced.css
 *
 * Usage:
 *   node scripts/generate-theme-template.js
 *
 * Re-run whenever tokens are added/removed/renamed (after rebuilding tokens):
 *   pnpm --filter @grasdouble/lufa_design-system-cli run generate:template
 */
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const DIST_DIR = path.join(__dirname, '../../tokens/dist');
const TEMPLATES_DIR = path.join(__dirname, '../src/templates');

// ── Template definitions ────────────────────────────────────────────────────────

const TEMPLATES = [
  {
    source: 'themeable-tokens-starter.css',
    output: 'theme-template.css',
    level: 'starter', // backwards-compat alias pointing to starter level
    headerTitle: 'Theme Template',
    headerDesc: 'Auto-generated from tokens/dist/themeable-tokens-starter.css.',
    headerNote: 'Starter level: minimum required tokens to create a functional theme (brand + feedback colors).',
  },
  {
    source: 'themeable-tokens-starter.css',
    output: 'theme-template-starter.css',
    level: 'starter',
    headerTitle: 'Theme Template — Starter Level',
    headerDesc: 'Auto-generated from tokens/dist/themeable-tokens-starter.css.',
    headerNote: 'Starter level: minimum required tokens to create a functional theme (brand + feedback colors).',
  },
  {
    source: 'themeable-tokens-extended.css',
    output: 'theme-template-extended.css',
    level: 'extended',
    headerTitle: 'Theme Template — Extended Level',
    headerDesc: 'Auto-generated from tokens/dist/themeable-tokens-extended.css.',
    headerNote: 'Extended level: cumulative — includes starter + extended tokens (adds alpha colors).',
  },
  {
    source: 'themeable-tokens-advanced.css',
    output: 'theme-template-advanced.css',
    level: 'advanced',
    headerTitle: 'Theme Template — Advanced Level',
    headerDesc: 'Auto-generated from tokens/dist/themeable-tokens-advanced.css.',
    headerNote: 'Advanced level: cumulative — includes starter + extended + advanced tokens (full control).',
  },
];

// ── Helpers ─────────────────────────────────────────────────────────────────────

const buildHeader = ({ headerTitle, headerDesc, headerNote }, now) => `/**
 * Lufa Design System - ${headerTitle}
 *
 * ${headerDesc}
 * Use this as a starting point for creating a new theme.
 * Generated: ${now}
 *
 * Instructions:
 *   1. Replace 'your-theme-name' with your theme identifier
 *   2. Override the tokens you need to change (defaults shown)
 *   3. ${headerNote}
 *
 * Validation:
 *   lufa-validate-theme path/to/your-theme.css
 */
`;

/** @param {string} css @returns {string} */
const stripAutoGeneratedComment = (css) =>
  css.replace(/^\/\*\*\n \* Do not edit directly, this file was auto-generated\.\n \*\/\n\n/, '');

/** @param {string} body @returns {number} */
const countTokens = (body) => [...body.matchAll(/--lufa-[a-z0-9-]+\s*:/g)].length / 3;

// ── Process templates ───────────────────────────────────────────────────────────

fs.mkdirSync(TEMPLATES_DIR, { recursive: true });

const now = new Date().toISOString();
let successCount = 0;
let skipCount = 0;

for (const tmpl of TEMPLATES) {
  const sourcePath = path.join(DIST_DIR, tmpl.source);
  const outputPath = path.join(TEMPLATES_DIR, tmpl.output);

  if (!fs.existsSync(sourcePath)) {
    console.warn(`⚠  Source not found, skipping: ${sourcePath}`);
    console.warn(`   Run: pnpm ds:tokens:build`);
    skipCount++;
    continue;
  }

  const rawCss = /** @type {string} */ (fs.readFileSync(sourcePath, 'utf-8'));
  const body = stripAutoGeneratedComment(rawCss);
  const header = buildHeader(tmpl, now);

  fs.writeFileSync(outputPath, header + body, 'utf-8');

  const tokenCount = Math.round(countTokens(body));
  const relOutput = path.relative(process.cwd(), outputPath);
  const levelTag = tmpl.level ? ` [${tmpl.level}]` : '';
  console.log(`✓ ${relOutput}${levelTag} (${tokenCount} tokens × 3 modes)`);
  successCount++;
}

// ── Summary ─────────────────────────────────────────────────────────────────────

if (successCount === 0) {
  throw new Error('✗ No templates generated — all source files were missing.\n  Run: pnpm ds:tokens:build');
}

if (skipCount > 0) {
  console.warn(`⚠  ${skipCount} template(s) skipped due to missing source files.`);
}

console.log(`\n✓ ${successCount}/${TEMPLATES.length} template(s) generated successfully.`);
